class Solution {
public:
    bool isPossible(vector<int>& nums) {
        map<int, int> count;
        map<int, int> seq;

        for (int num : nums) {
            count[num]++;
        }

        for (int num : nums) {
            if (count[num] == 0) {
                continue;
            }
            if (seq[num - 1] > 0) {
                seq[num - 1]--;
                seq[num]++;
                count[num]--;
            } else if (count[num] > 0 && count[num + 1] > 0 && count[num + 2] > 0) {
                count[num]--;
                count[num + 1]--;
                count[num + 2]--;
                seq[num + 3]++;
            } else {
                return false;
            }
        }

        return true;
    }
};

